// Generates `src/content-bundle.ts` from every `*.md` file under `content/`.
//
// The help panel must work both in dev (running from src/) and inside the
// bundled CLI (where help-core is inlined into a chunk file alongside no
// content/ directory). Reading from disk via `import.meta.url` is fragile
// in the bundled case, so we inline the markdown into a TS module that
// travels with the code wherever tsup/esbuild ships it.
//
// Re-run automatically via the `prebuild` npm script before `tsup`.

import { readFileSync, readdirSync, writeFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const contentDir = join(here, '..', 'content');
const outFile = join(here, '..', 'src', 'content-bundle.ts');

const files = readdirSync(contentDir)
  .filter((f) => f.endsWith('.md'))
  .sort();

const entries = files.map((file) => {
  const id = file.replace(/\.md$/, '');
  const raw = readFileSync(join(contentDir, file), 'utf-8');
  // JSON.stringify gives us correct escaping for newlines, quotes, and
  // unicode — perfect for embedding arbitrary markdown as a string literal.
  return `  ${JSON.stringify(id)}: ${JSON.stringify(raw)},`;
});

const banner = `// AUTO-GENERATED by scripts/generate-content-bundle.mjs — DO NOT EDIT.
// Re-run via \`npm run prebuild\` (invoked automatically before \`npm run build\`).
// Source files live in packages/help-core/content/*.md.
`;

const body = `${banner}
export const HELP_CONTENT: Record<string, string> = {
${entries.join('\n')}
};
`;

writeFileSync(outFile, body, 'utf-8');
console.log(`help-core: bundled ${files.length} markdown files → ${outFile}`);
